mapper.select:
SELECT t.id, t.ticket_no, t.business_domain_id, d.code AS business_domain_code, d.name AS business_domain_name, t.ticket_type_id, tt.name AS ticket_type_name, t.customer_id, t.assigned_to, t.title, t.description, t.status, t.priority, t.source, t.result, t.version, CAST(t.custom_fields AS CHAR) AS custom_fields_json, t.sla_first_response_deadline, t.sla_resolution_deadline, t.sla_first_responded_at, t.sla_resolved_at, t.sla_status, t.sla_paused_duration, t.sla_pause_started_at, t.created_at, t.updated_at, ( SELECT MAX(r.created_at) FROM ticket_reply r WHERE r.ticket_id = t.id ) AS last_reply_at, COALESCE(( SELECT COUNT(*) FROM ticket_reply r WHERE r.ticket_id = t.id ), 0) AS reply_count FROM ticket t JOIN business_domain d ON d.id = t.business_domain_id JOIN ticket_type tt ON tt.id = t.ticket_type_id WHERE t.business_domain_id = #{domainId}
AND t.customer_id = #{customerId}
AND t.status = #{status}
ORDER BY t.updated_at DESC, t.id DESC LIMIT #{limit}

SELECT id
FROM ticket
WHERE ticket_no = #{ticketNo}

SELECT COALESCE(MAX(CAST(SUBSTRING_INDEX(ticket_no, '-', -1) AS UNSIGNED)), 0) + 1
FROM ticket
WHERE business_domain_id = #{domainId} AND ticket_no LIKE #{prefix}
